+    case "PREVIOUS_QUESTION":
+      if (state.currentQuestionIndex > 0) {
+        return {
+          ...state,
+          currentQuestionIndex: state.currentQuestionIndex - 1,
+          questionStartTime: Date.now(),
+        };
+      }
+      return state;
+
+    case "FINISH_SENTENCE":
+      return {
+        ...state,
+        isSentenceComplete: true,
+      };
+
+    case "RESTART_SENTENCE":
+      return {
+        currentQuestionIndex: 0,
+        userSentence: "",
+        showResult: false,
+        score: 0,
+        answeredQuestions: new Array(action.payload.questionCount).fill(false),
+        userAnswers: new Array(action.payload.questionCount).fill(""),
+        isSentenceComplete: false,
+        showUserSentences: {},
+        questionStartTime: Date.now(),
+        restartKey: Date.now(),
+        isSubmitting: false,
+        feedbackByQuestion: {},
+      };
+
+    case "TOGGLE_USER_SENTENCES":
+      return {
+        ...state,
+        showUserSentences: {
+          ...state.showUserSentences,
+          [action.payload]: !state.showUserSentences[action.payload],
+        },
+      };
+
+    case "SET_QUESTION_START_TIME":
+      return {
+        ...state,
+        questionStartTime: action.payload,
+      };
+
+    case "LOAD_QUESTION_STATE":
+      return {
+        ...state,
+        userSentence: action.payload.userSentence,
+        showResult: action.payload.showResult,
+        isSubmitting: false,
+      };
+
+    default:
+      return state;
+  }
+}
+
+function calculateMasteryLevel(
+  correctAttempts: number,
+  totalAttempts: number,
+  consecutiveCorrect: number
+): WordPerformance["masteryLevel"] {
+  if (totalAttempts === 0) return "learning";
+
+  const accuracy = correctAttempts / totalAttempts;
+
+  if (accuracy >= 0.9 && consecutiveCorrect >= 3) return "mastered";
+  if (accuracy >= 0.7 && consecutiveCorrect >= 2) return "proficient";
+  if (accuracy >= 0.5) return "learning";
+  return "struggling";
+}
+
+function wordRegex(word: string) {
+  return new RegExp(
+    `\\b${word.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`,
+    "i"
+  );
+}
+
+function evaluateSentenceLocally(
+  sentence: string,
+  word: VocabularyWord
+): SentenceFeedback {
+  const trimmedSentence = sentence.trim();
+  const words = trimmedSentence.match(/[A-Za-z]+(?:'[A-Za-z]+)?/g) || [];
+  const includesWord = wordRegex(word.word).test(trimmedSentence);
+  const hasEnoughContext = words.length >= 6;
+  const hasSentencePunctuation = /[.!?]$/.test(trimmedSentence);
+
+  if (!includesWord) {
+    return {
+      correct: false,
+      exampleSentence: word.example,
+      aiResponse: `Use "${word.word}" directly in your sentence so the tutor can check it.`,
+      hint: `Try writing a sentence that includes "${word.word}" and shows its meaning.`,
+    };
+  }
+
+  if (!hasEnoughContext) {
+    return {
+      correct: false,
+      exampleSentence: word.example,
+      aiResponse:
+        "This looks too short to show the word's meaning clearly. Add more context around the vocabulary word.",
+      hint: `Show a situation where "${word.word}" means ${word.definition}.`,
+    };
+  }
+
+  if (!hasSentencePunctuation) {
+    return {
+      correct: false,
+      exampleSentence: word.example,
+      aiResponse:
+        "This is close, but make it a complete sentence with ending punctuation.",
+      hint: "Add a period, question mark, or exclamation point after a complete thought.",
+    };
+  }
+
+  return {
+    correct: true,
+    exampleSentence: word.example,
+    aiResponse:
+      "Basic check passed. The sentence includes the vocabulary word in a complete sentence.",
+    hint: "",
+  };
+}
+
+function normalizeSentence(sentence: string) {
+  return sentence.trim().replace(/\s+/g, " ");
+}
+
+function isValidFeedbackResult(
+  result: unknown
+): result is SentenceFeedback {
+  if (!result || typeof result !== "object") return false;
+
+  const feedback = result as Partial<SentenceFeedback>;
+  return (
+    typeof feedback.correct === "boolean" &&
+    typeof feedback.exampleSentence === "string" &&
+    typeof feedback.aiResponse === "string" &&
+    typeof feedback.hint === "string"
+  );
+}
