+import { createOpenRouter } from "@openrouter/ai-sdk-provider";
+import { generateObject } from "ai";
+import { NextRequest, NextResponse } from "next/server";
+import { z } from "zod";
+
+export const runtime = "nodejs";
+
+const SUPPORTED_TASKS = [
+  "validate-user-definition",
+  "validate-user-sentence",
+] as const;
+
+const feedbackSchema = z.object({
+  correct: z.boolean(),
+  exampleSentence: z.string(),
+  aiResponse: z.string(),
+  hint: z.string(),
+});
+
+type FeedbackResult = z.infer<typeof feedbackSchema>;
+
+function failureResponse(message: string, status: number) {
+  return NextResponse.json({ success: false, message }, { status });
+}
+
+function getStringField(
+  data: Record<string, unknown> | undefined,
+  key: string
+) {
+  const value = data?.[key];
+  return typeof value === "string" ? value.trim() : "";
+}
+
+function validateTask(task: unknown) {
+  if (typeof task !== "string" || task.trim().length === 0) {
+    return {
+      ok: false as const,
+      response: failureResponse(
+        `Missing task. Expected one of: ${SUPPORTED_TASKS.join(", ")}.`,
+        400
+      ),
+    };
+  }
+
+  if (!SUPPORTED_TASKS.includes(task as (typeof SUPPORTED_TASKS)[number])) {
+    return {
+      ok: false as const,
+      response: failureResponse(
+        `Unsupported task "${task}". Expected one of: ${SUPPORTED_TASKS.join(
+          ", "
+        )}.`,
+        400
+      ),
+    };
+  }
+
+  return {
+    ok: true as const,
+    task: task as (typeof SUPPORTED_TASKS)[number],
+  };
+}
+
+function buildDefinitionPrompt(data: Record<string, unknown> | undefined) {
+  const word = getStringField(data, "word");
+  const userDefinition = getStringField(data, "userDefinition");
+  const correctDefinition = getStringField(data, "correctDefinition");
+  const exampleSentence = getStringField(data, "exampleSentence");
+
+  if (!word || !userDefinition || !correctDefinition) {
+    return {
+      ok: false as const,
+      response: failureResponse(
+        "Missing required definition validation fields: word, userDefinition, correctDefinition.",
+        400
+      ),
+    };
+  }
+
+  return {
+    ok: true as const,
+    prompt: `
+Evaluate a learner's vocabulary definition.
+
+Word: ${word}
+Correct definition: ${correctDefinition}
+Dictionary example: ${exampleSentence || "Not provided"}
+Learner definition: ${userDefinition}
+
+Return whether the learner's definition captures the main meaning. Be lenient
+about wording, but mark it incorrect if it means a different concept or is too
+vague. Give brief tutor-style feedback, a concise hint if incorrect, and a
+natural example sentence using the word.
+`,
+  };
+}
+
+function buildSentencePrompt(data: Record<string, unknown> | undefined) {
+  const word = getStringField(data, "word");
+  const userSentence = getStringField(data, "userSentence");
+  const correctDefinition = getStringField(data, "correctDefinition");
+  const exampleSentence = getStringField(data, "exampleSentence");
+  const partOfSpeech = getStringField(data, "partOfSpeech");
+
+  if (!word || !userSentence || !correctDefinition) {
+    return {
+      ok: false as const,
+      response: failureResponse(
+        "Missing required sentence validation fields: word, userSentence, correctDefinition.",
+        400
+      ),
+    };
+  }
+
+  return {
+    ok: true as const,
+    prompt: `
+Evaluate a learner's original vocabulary sentence.
+
+Word: ${word}
+Part of speech: ${partOfSpeech || "Not provided"}
+Definition: ${correctDefinition}
+Dictionary example: ${exampleSentence || "Not provided"}
+Learner sentence: ${userSentence}
+
+Mark correct only if the sentence uses the vocabulary word in a complete,
+natural sentence and the context shows the intended meaning. Do not require the
+sentence to be perfect, but reject fragments, definition copying, or sentences
+where the word's meaning is unclear. Give brief tutor-style feedback, a concise
+hint if incorrect, and a model example sentence.
+`,
+  };
+}
+
+async function requestFeedback(prompt: string): Promise<FeedbackResult> {
+  const apiKey = process.env.OPENROUTER_KEY;
+
+  if (!apiKey) {
+    throw new Error("OPENROUTER_KEY is not configured");
+  }
+
+  const openrouter = createOpenRouter({ apiKey });
+  const { object } = await generateObject({
+    model: openrouter(process.env.OPENROUTER_MODEL || "openai/gpt-4o-mini"),
+    schema: feedbackSchema,
+    mode: "json",
+    temperature: 0.2,
+    maxOutputTokens: 500,
+    system:
+      "You are a concise vocabulary tutor. Return only the requested structured result.",
+    prompt,
+  });
+
+  return object;
+}
+
+export async function POST(request: NextRequest) {
+  let body: unknown;
+
+  try {
+    body = await request.json();
+  } catch {
+    return failureResponse("Invalid JSON request body.", 400);
+  }
+
+  const parsedBody = z
+    .object({
+      task: z.unknown(),
+      data: z.record(z.string(), z.unknown()).optional(),
+    })
+    .safeParse(body);
+
+  if (!parsedBody.success) {
+    return failureResponse("Request body must include a task and data object.", 400);
+  }
+
+  const taskResult = validateTask(parsedBody.data.task);
+  if (!taskResult.ok) {
+    return taskResult.response;
+  }
+
+  const promptResult =
+    taskResult.task === "validate-user-definition"
+      ? buildDefinitionPrompt(parsedBody.data.data)
+      : buildSentencePrompt(parsedBody.data.data);
+
+  if (!promptResult.ok) {
+    return promptResult.response;
+  }
+
+  try {
+    const result = await requestFeedback(promptResult.prompt);
+    return NextResponse.json({ success: true, result });
+  } catch (error) {
+    console.error("Vocabulary feedback generation failed:", error);
+    return failureResponse(
+      "Unable to generate vocabulary feedback right now.",
+      500
+    );
+  }
